package data_migration

import (
	"airwatch/uem/gumdrop-ingestion/internal/pkg/emitter"
	"airwatch/uem/gumdrop-ingestion/pkg/log"
	"fmt"
)

// Migration defines the contract that all data migrations must implement.
type Migration interface {
	// Name returns the name of the migration (without version).
	Name() string

	// Version returns the version of the migration.
	Version() int

	// ID returns a unique identifier for the migration (combines name and version).
	ID() string

	// Description returns a human-readable description of what the migration does.
	Description() string

	// Execute runs the migration with the provided dependencies.
	Execute(ctx *log.Context, queryEmitter emitter.Emitter) error
}

// BaseMigration provides a basic implementation of the Migration interface.
type BaseMigration struct {
	name        string
	version     int
	description string
}

// NewBaseMigration creates a new base migration with the given properties.
func NewBaseMigration(name string, version int, description string) BaseMigration {
	return BaseMigration{
		name:        name,
		version:     version,
		description: description,
	}
}

// Name returns the migration name.
func (m BaseMigration) Name() string {
	return m.name
}

// Version returns the migration version.
func (m BaseMigration) Version() int {
	return m.version
}

// ID returns the unique identifier for this migration (name:version).
func (m BaseMigration) ID() string {
	return fmt.Sprintf("%s:v%d", m.name, m.version)
}

// Description returns the migration description.
func (m BaseMigration) Description() string {
	return m.description
}
