// MockConsulClient is a mock implementation of consul.Client interface
type MockConsulClient struct {
	mock.Mock
}

// NewMockConsulClient creates a new instance of MockConsulClient
func NewMockConsulClient() *MockConsulClient {
	return &MockConsulClient{}
}

func (m *MockConsulClient) Address() string {
	args := m.Called()
	return args.String(0)
}

func (m *MockConsulClient) RunOnceAction(ctx *log.Context, name string, action func() error, othersAction func() error) (<-chan error, error) {
	args := m.Called(ctx, name, action, othersAction)
	if args.Get(0) == nil {
		return nil, args.Error(1)
	}
	return args.Get(0).(chan error), args.Error(1)
}

func (m *MockConsulClient) GetKey(key string) (*api.KVPair, error) {
	args := m.Called(key)
	if args.Get(0) == nil {
		return nil, args.Error(1)
	}
	return args.Get(0).(*api.KVPair), args.Error(1)
}

func (m *MockConsulClient) PutKey(key string, value interface{}) error {
	args := m.Called(key, value)
	return args.Error(0)
}

func (m *MockConsulClient) DeleteKey(key string) error {
	args := m.Called(key)
	return args.Error(0)
