// MockMigration is a mock implementation of the Migration interface
type MockMigration struct {
	NameVal        string
	VersionVal     int
	DescriptionVal string
	ExecuteFn      func(ctx *log.Context, queryEmitter emitter.Emitter) error
}

func (m *MockMigration) Name() string {
	return m.NameVal
}

func (m *MockMigration) Version() int {
	return m.VersionVal
}

func (m *MockMigration) ID() string {
	return m.NameVal + ":v" + string(rune(m.VersionVal+'0'))
}

func (m *MockMigration) Description() string {
	return m.DescriptionVal
}

func (m *MockMigration) Execute(ctx *log.Context, queryEmitter emitter.Emitter) error {
	if m.ExecuteFn != nil {
		return m.ExecuteFn(ctx, queryEmitter)
	}
	return nil
}

// MockEmitter is a mock implementation of the emitter.Emitter interface
type MockEmitter struct {
	mock.Mock
}

func (m *MockEmitter) Emit(obj interface{}) (interface{}, error) {
	args := m.Called(obj)
	return args.Get(0), args.Error(1)
}

func TestRegister(t *testing.T) {
	// Reset the migration registry before each test
	data_migration.ResetRegistry()

	tests := []struct {
		name        string
		migration   data_migration.Migration
		expectError bool
		errorMsg    string
	}{
		{
			name: "valid migration",
			migration: &MockMigration{
				NameVal:        "test-migration",
				VersionVal:     1,
				DescriptionVal: "Test migration",
			},
			expectError: false,
		},
		{
			name:        "nil migration",
			migration:   nil,
			expectError: true,
			errorMsg:    "migration cannot be nil",
		},
		{
			name: "empty name",
			migration: &MockMigration{
				NameVal:        "",
				VersionVal:     1,
				DescriptionVal: "Test migration",
			},
			expectError: true,
			errorMsg:    "migration name cannot be empty",
		},
		{
			name: "invalid version",
			migration: &MockMigration{
				NameVal:        "test-migration",
				VersionVal:     0,
				DescriptionVal: "Test migration",
			},
			expectError: true,
			errorMsg:    "migration version must be greater than 0",
		},
		{
			name: "duplicate migration",
			migration: &MockMigration{
				NameVal:        "duplicate",
				VersionVal:     1,
				DescriptionVal: "Duplicate migration",
			},
			expectError: true,
			errorMsg:    "migration with ID duplicate:v1 is already registered",
		},
	}

	// Register the duplicate migration for the duplicate test case
	duplicateMigration := &MockMigration{
		NameVal:        "duplicate",
		VersionVal:     1,
		DescriptionVal: "Original migration",
	}
	err := data_migration.Register(duplicateMigration)
	require.NoError(t, err)

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := data_migration.Register(tt.migration)
			if tt.expectError {
				assert.Error(t, err)
				assert.Contains(t, err.Error(), tt.errorMsg)
			} else {
				assert.NoError(t, err)
			}
		})
	}
}

func TestRunMigrations(t *testing.T) {
	logContext := log.NewContext()
	mockEmitter := &MockEmitter{}
	mockConsul := mock_consul.NewMockConsulClient()

	tests := []struct {
		name             string
		migrations       []data_migration.Migration
		consulGetValue   *api.KVPair
		consulGetError   error
		consulPutError   error
		migrationErrors  map[string]error
		expectFinalError bool
	}{
		{
			name:             "no migrations",
			migrations:       []data_migration.Migration{},
			consulGetValue:   nil,
			consulGetError:   nil,
			expectFinalError: false,
		},
		{
			name: "successful migrations",
			migrations: []data_migration.Migration{
				&MockMigration{
					NameVal:        "migration1",
					VersionVal:     1,
					DescriptionVal: "First migration",
				},
				&MockMigration{
					NameVal:        "migration2",
					VersionVal:     1,
					DescriptionVal: "Second migration",
				},
			},
			consulGetValue:   nil,
			consulGetError:   nil,
			expectFinalError: false,
		},
		{
			name: "consul get error",
			migrations: []data_migration.Migration{
				&MockMigration{
					NameVal:        "migration1",
					VersionVal:     1,
					DescriptionVal: "First migration",
				},
			},
			consulGetValue:   nil,
			consulGetError:   errors.New("consul get error"),
			expectFinalError: true,
		},
		{
			name: "consul put error",
			migrations: []data_migration.Migration{
				&MockMigration{
					NameVal:        "migration1",
					VersionVal:     1,
					DescriptionVal: "First migration",
				},
			},
			consulGetValue:   nil,
			consulGetError:   nil,
			consulPutError:   errors.New("consul put error"),
			expectFinalError: true,
		},
		{
			name: "migration execution error",
			migrations: []data_migration.Migration{
				&MockMigration{
					NameVal:        "migration1",
					VersionVal:     1,
					DescriptionVal: "First migration",
				},
				&MockMigration{
					NameVal:        "migration2",
					VersionVal:     1,
					DescriptionVal: "Second migration",
				},
			},
			consulGetValue: nil,
			consulGetError: nil,
			migrationErrors: map[string]error{
				"migration2:v1": errors.New("migration execution error"),
			},
			expectFinalError: true,
		},
		{
			name: "skip already executed migrations",
			migrations: []data_migration.Migration{
				&MockMigration{
					NameVal:        "migration1",
					VersionVal:     1,
					DescriptionVal: "First migration",
				},
				&MockMigration{
					NameVal:        "migration2",
					VersionVal:     1,
					DescriptionVal: "Second migration",
				},
			},
			consulGetValue: createHistoryKVPair(map[string]bool{
				"migration1:v1": true,
			}),
			consulGetError:   nil,
			expectFinalError: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Reset registry
			data_migration.ResetRegistry()

			// Setup mocks
			mockConsul.On("GetKey", data_migration.MigrationHistoryKey).Return(tt.consulGetValue, tt.consulGetError).Once()

			// Setup migrations with execution behavior
			for _, migration := range tt.migrations {
				m := migration.(*MockMigration)
				m.ExecuteFn = func(ctx *log.Context, queryEmitter emitter.Emitter) error {
					if tt.migrationErrors != nil {
						if err, ok := tt.migrationErrors[m.ID()]; ok {
							return err
						}
					}
					return nil
				}

				err := data_migration.Register(migration)
				require.NoError(t, err)
			}

			// Setup consul PutKey behavior if we expect migrations to run
			if !tt.expectFinalError && len(tt.migrations) > 0 && tt.consulGetError == nil {
				mockConsul.On("PutKey", data_migration.MigrationHistoryKey, mock.Anything).Return(tt.consulPutError).Once()
			}

			// Run migrations
			err := data_migration.RunMigrations(logContext, mockEmitter, mockConsul)

			// Verify results
			if tt.expectFinalError {
				assert.Error(t, err)
			} else {
				assert.NoError(t, err)
			}

			// Verify mocks
			mockConsul.AssertExpectations(t)
		})
	}
}

func TestBaseMigration(t *testing.T) {
	tests := []struct {
		name        string
		migration   data_migration.BaseMigration
		expectedID  string
		expectedStr string
	}{
		{
			name:       "basic migration",
			migration:  data_migration.NewBaseMigration("test", 1, "Test migration"),
			expectedID: "test:v1",
		},
		{
			name:       "migration with version 10",
			migration:  data_migration.NewBaseMigration("foo", 10, "Version 10 migration"),
			expectedID: "foo:v10",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			assert.Equal(t, tt.migration.Name(), tt.migration.Name())
			assert.Equal(t, tt.migration.Version(), tt.migration.Version())
			assert.Equal(t, tt.migration.Description(), tt.migration.Description())
			assert.Equal(t, tt.expectedID, tt.migration.ID())
		})
	}
}

// Helper to create a KVPair with migration history
func createHistoryKVPair(migrations map[string]bool) *api.KVPair {
	history := map[string]data_migration.MigrationInfo{}

	for id := range migrations {
		history[id] = data_migration.MigrationInfo{
			Name:    "Test",
			Version: 1,
			ID:      id,
		}
	}

	historyBytes, _ := json.Marshal(map[string]interface{}{
		"migrations": history,
	})

	return &api.KVPair{
		Key:   data_migration.MigrationHistoryKey,
		Value: historyBytes,
	}
}
