func TestGetExecutedMigrations(t *testing.T) {
	logContext := log.NewContext()
	mockConsul := mock_consul.NewMockConsulClient()

	tests := []struct {
		name           string
		consulResponse *api.KVPair
		consulError    error
		expectedMigrations int
		expectError    bool
	}{
		{
			name:           "successful retrieval",
			consulResponse: createMigrationHistoryKVPair(2),
			consulError:    nil,
			expectedMigrations: 2,
			expectError:    false,
		},
		{
			name:           "empty history",
			consulResponse: &api.KVPair{Key: data_migration.MigrationHistoryKey, Value: []byte("{}")},
			consulError:    nil,
			expectedMigrations: 0,
			expectError:    false,
		},
		{
			name:           "nil response",
			consulResponse: nil,
			consulError:    nil,
			expectedMigrations: 0,
			expectError:    false,
		},
		{
			name:           "consul error",
			consulResponse: nil,
			consulError:    errors.New("consul error"),
			expectedMigrations: 0,
			expectError:    true,
		},
		{
			name:           "invalid json",
