func TestRegister(t *testing.T) {
	// Reset the migration registry before each test
	ResetRegistry()

	tests := []struct {
		name        string
		migration   Migration
		expectError bool
		errorMsg    string
	}{
		{
			name: "valid migration",
			migration: &mockMigration{
				NameVal:        "test-migration",
				VersionVal:     1,
				DescriptionVal: "Test migration",
			},
			expectError: false,
		},
		{
			name:        "nil migration",
			migration:   nil,
			expectError: true,
			errorMsg:    "migration cannot be nil",
		},
		{
			name: "empty name",
			migration: &mockMigration{
				NameVal:        "",
				VersionVal:     1,
				DescriptionVal: "Test migration",
			},
			expectError: true,
			errorMsg:    "migration name cannot be empty",
		},
		{
			name: "invalid version",
			migration: &mockMigration{
				NameVal:        "test-migration",
				VersionVal:     0,
				DescriptionVal: "Test migration",
			},
			expectError: true,
			errorMsg:    "migration version must be greater than 0",
		},
		{
			name: "duplicate migration",
			migration: &mockMigration{
				NameVal:        "duplicate",
				VersionVal:     1,
				DescriptionVal: "Duplicate migration",
			},
			expectError: true,
			errorMsg:    "migration with ID duplicate:v1 is already registered",
		},
	}

	// Register the duplicate migration for the duplicate test case
	duplicateMigration := &mockMigration{
		NameVal:        "duplicate",
		VersionVal:     1,
		DescriptionVal: "Original migration",
	}
	err := Register(duplicateMigration)
	require.NoError(t, err)

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := Register(tt.migration)
			if tt.expectError {
				assert.Error(t, err)
				assert.Contains(t, err.Error(), tt.errorMsg)
			} else {
				assert.NoError(t, err)
			}
		})
	}
}

