			if migrationError != nil {
				log.Errorw(logContext, "Failed to save migration history after a migration error",
					"error", saveErr)
				return migrationError
			}
			return errors.Wrapf(saveErr, "%s: Failed to save updated migration history", functionName)
		}
	}

