// deleteEmptyDocumentsMigration deletes empty documents from the database.
type deleteEmptyDocumentsMigration struct {
	dataMigration.BaseMigration
}

// newDeleteEmptyDocumentsMigration creates a new instance of the migration.
func newDeleteEmptyDocumentsMigration() dataMigration.Migration {
	return &deleteEmptyDocumentsMigration{
		BaseMigration: dataMigration.NewBaseMigration(
			"DeleteEmptyDocuments",
			1,
			"Deletes empty documents from the database",
		),
	}
}

var (
	requiredProperties = []string{"tenant_uuid"}
	indices            = []string{env.LookupValue(pkg.IndexPatternEnv, "*")}
)

// Execute runs the migration
func (m *deleteEmptyDocumentsMigration) Execute(logContext *log.Context, queryEmitter emitter.Emitter) error {
	queryModel := &repository.QueryModel{
		DeleteByQuery: []*repository.QueryDetailsItem[*repository.QueryRequest[repository.NoParams]]{
			{
				Indices: indices,
				Body: repository.NewMissingOrDefaultPropertiesQueryRequest[repository.NoParams](
					logContext,
					nil,
					nil,
					requiredProperties,
					nil,
				),
				LogContext: logContext,
			},
		},
		DeleteByQueryIndices: set.New(1, indices...),
	}

	auditInfo := map[string][]emitter.AuditLogDetails{
		pkg2.DeleteByQueryOperationId: make([]emitter.AuditLogDetails, 0),
	}

	if err := queryEmitter.EmitDeleteByQuery(logContext, queryModel, auditInfo, false); err != nil {
		return err
	}

	return nil
}
