func TestNewDeleteEmptyDocumentsMigration(t *testing.T) {
	migration := newDeleteEmptyDocumentsMigration()

	assert.Equal(t, "DeleteEmptyDocuments", migration.Name())
	assert.Equal(t, 1, migration.Version())
	assert.Equal(t, "DeleteEmptyDocuments:v1", migration.ID())
	assert.Equal(t, "Deletes empty documents from the database", migration.Description())
}

func TestDeleteEmptyDocumentsMigration_Execute(t *testing.T) {
	tests := []struct {
		name            string
		emitError       error
		expectError     bool
		indexEnvValue   string
		expectedIndices []string
	}{
		{
			name:            "successful execution",
			emitError:       nil,
			expectError:     false,
			indexEnvValue:   "*uem.gumdrop*",
			expectedIndices: []string{"*uem.gumdrop*"},
		},
		{
			name:            "emit error",
			emitError:       errors.New("emit error"),
			expectError:     true,
			indexEnvValue:   "*uem.gumdrop*",
			expectedIndices: []string{"*uem.gumdrop*"},
		},
		{
			name:            "default index pattern",
			emitError:       nil,
			expectError:     false,
			indexEnvValue:   "",
			expectedIndices: []string{"*"},
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Setup
			logContext := log.NewLogContextWithCorrelationIds("test-correlation-id")
			mockEmit := mockEmitter.NewMockEmitter()

			// Save original env value
			origValue := os.Getenv("INDEX_PATTERN")

			// Set env value for test
			os.Setenv("INDEX_PATTERN", tt.indexEnvValue)

			// Restore env after test
			defer os.Setenv("INDEX_PATTERN", origValue)

			migration := newDeleteEmptyDocumentsMigration()

			// Set up expectations - use proper mock setup
			mockEmit.On("EmitDeleteByQuery", 
				mock.AnythingOfType("*log.Context"), 
				mock.MatchedBy(func(qm *repository.QueryModel) bool {
					// Validate indices
					if len(qm.DeleteByQuery) != 1 {
						return false
					}

					expectedIndex := tt.expectedIndices[0]
					if tt.indexEnvValue == "" {
						expectedIndex = "*" // Default when not set
					}

					if len(qm.DeleteByQuery[0].Indices) != 1 || qm.DeleteByQuery[0].Indices[0] != expectedIndex {
						return false
					}

					return true
				}),
				mock.AnythingOfType("map[string][]emitter.AuditLogDetails"),
				false,
			).Return(tt.emitError)

			// Execute
			err := migration.Execute(logContext, mockEmit)

			// Verify
			if tt.expectError {
				assert.Error(t, err)
				assert.Equal(t, tt.emitError, err)
			} else {
				assert.NoError(t, err)
			}

			mockEmit.AssertExpectations(t)
		})
	}
}
