To run specific migrations for integration testing, we can enhance the data migration system to support selective execution of migrations by name or ID. Here's how we can implement this:

First, let's add a new function to the `data_migration` package:

```go
// gumdrop/internal/pkg/repository/data-migration/runner.go

// Add this function to the existing file:

// RunSpecificMigrations executes only the specified migrations
// This is primarily used for testing purposes
func RunSpecificMigrations(
	logContext *log.Context,
	queryEmitter emitter.Emitter,
	consulClient consul.Client,
	migrationIDs []string,
) error {
	const functionName = "data_migration.RunSpecificMigrations"

	if len(migrationIDs) == 0 {
		log.Infof(logContext, "%s: No migration IDs provided, skipping migration process", functionName)
		return nil
	}

	// Create storage for migration history
	storage := newStorage(consulClient)

	// Load migration history
	executedMigrations, err := storage.GetExecutedMigrations(logContext)
	if err != nil {
		return errors.Wrapf(err, "%s: Failed to load migration history", functionName)
	}

	log.Infow(logContext, fmt.Sprintf("%s: Loaded migration history", functionName),
		"executed_count", len(executedMigrations))

	// Track if we've modified the history
	historyModified := false

	// Function to save history and handle the error
	saveHistory := func() error {
		if !historyModified {
			return nil
		}

		history := migrationHistory{
			Migrations: executedMigrations,
		}

		if err := storage.SaveMigrationHistory(logContext, history); err != nil {
			return errors.Wrapf(err, "%s: Failed to save updated migration history", functionName)
		}
		return nil
	}

	// Create a map for fast lookup of requested migrations
	requestedMigrations := make(map[string]bool)
	for _, id := range migrationIDs {
		requestedMigrations[id] = true
	}

	// Execute only the requested migrations if they haven't been executed yet
	for _, migration := range migrationRegistry.migrations {
		migrationID := migration.ID()

		// Skip if not in the requested list
		if !requestedMigrations[migrationID] {
			continue
		}

		// Check if already executed
		_, alreadyExecuted := executedMigrations[migrationID]

		if alreadyExecuted {
			log.Infow(logContext, fmt.Sprintf("%s: Skipping already executed migration", functionName),
				"migration_id", migrationID,
				"migration_name", migration.Name(),
				"migration_version", migration.Version())
			continue
		}

		log.Infow(logContext, fmt.Sprintf("%s: Executing migration", functionName),
			"migration_id", migrationID,
			"migration_name", migration.Name(),
			"migration_version", migration.Version(),
			"migration_description", migration.Description())

		startTime := time.Now()

		// Execute the migration
		if err := migration.Execute(logContext, queryEmitter); err != nil {
			// Save any successful migrations before returning the error
			if saveErr := saveHistory(); saveErr != nil {
				log.Errorw(logContext, fmt.Sprintf("%s: Failed to save migration history after a migration error", functionName),
					log.ErrorKey, saveErr,
					"migration_error", err)
			}
			return errors.Wrapf(err, "%s: Failed to execute migration %s",
				functionName, migrationID)
		}

		// Create migration info
		info := migrationInfo{
			Name:        migration.Name(),
			Version:     migration.Version(),
			ID:          migrationID,
			Description: migration.Description(),
			ExecutedAt:  time.Now(),
			DurationMs:  time.Since(startTime).Milliseconds(),
		}

		// Add to our local copy of executed migrations
		executedMigrations[migrationID] = info
		historyModified = true

		log.Infow(logContext, fmt.Sprintf("%s: Migration completed successfully", functionName),
			"migration_id", migrationID,
			"migration_name", migration.Name(),
			"migration_version", migration.Version(),
			"duration_ms", info.DurationMs)
	}

	// Save updated history back to Consul if we made changes
	if err := saveHistory(); err != nil {
		return err
	}

	log.Infof(logContext, "%s: Completed specific migrations", functionName)

	return nil
}
