Next, let's add a helper function to get a specific migration by name:

```go
// gumdrop/internal/pkg/repository/data-migration/runner.go

// Add this function to the existing file:

// GetMigrationIDByName returns the ID of a migration with the given name
// Returns an empty string if no migration with that name is found
func GetMigrationIDByName(name string) string {
	for _, migration := range migrationRegistry.migrations {
		if migration.Name() == name {
			return migration.ID()
		}
	}
	return ""
}
